import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

import facebookIcon from '../assets/facebook.jpeg';
import googleIcon from '../assets/google.jpeg';
import emailIcon from '../assets/email.jpeg';
import phoneIcon from '../assets/phone.jpeg';

// Validation helpers for email or phone input.
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const phoneRegex = /^\+?\d{8,15}$/;

const normalizePhone = (value = '') => value.replace(/[\s\-()]/g, '');

export default function CustomerLogin() {
  const navigate = useNavigate();
  const { login } = useAuth();

  const [formData, setFormData] = useState({
    identifier: '',
    password: '',
  });

  const [errorMessage, setErrorMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Update the field value and clear the current error message.
  const handleChange = (e) => {
    setErrorMessage('');
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  // Check whether the user typed a valid email or a valid phone number.
  const isValidIdentifier = (value) => {
    const cleanValue = value.trim();
    return emailRegex.test(cleanValue) || phoneRegex.test(normalizePhone(cleanValue));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!isValidIdentifier(formData.identifier)) {
      setErrorMessage('Please enter a valid email address or phone number.');
      return;
    }

    if (!formData.password || formData.password.length < 6) {
      setErrorMessage('Please enter a valid password.');
      return;
    }

    try {
      setIsSubmitting(true);
      setErrorMessage('');

      const response = await axiosInstance.post('/api/auth/customer/login', formData);

      // Save auth data into the existing auth layer.
      login(response.data);

      // Redirect to the customer home page after login.
      navigate('/tasks');
    } catch (error) {
      const serverMessage =
        error?.response?.data?.message || 'Login failed. Please check your details and try again.';
      setErrorMessage(serverMessage);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#efefef] flex items-center justify-center px-4">
      <div className="w-[390px] min-h-[844px] bg-white px-[14px] pt-[10px] pb-[18px] flex flex-col">
        {/* iPhone 14 status bar */}
        <div className="flex items-center justify-between px-[2px]">
          <span className="text-[16px] font-semibold tracking-[-0.2px] text-black">
            9:41
          </span>

          <div className="flex items-center gap-[6px]">
            <svg width="18" height="12" viewBox="0 0 18 12" fill="none">
              <rect x="1" y="7" width="2.2" height="4" rx="1" fill="#000000" />
              <rect x="5" y="5.5" width="2.2" height="5.5" rx="1" fill="#000000" />
              <rect x="9" y="4" width="2.2" height="7" rx="1" fill="#000000" />
              <rect x="13" y="2.5" width="2.2" height="8.5" rx="1" fill="#000000" />
            </svg>

            <svg width="16" height="12" viewBox="0 0 16 12" fill="none">
              <path
                d="M1 4.5C4.7 1.4 11.3 1.4 15 4.5"
                stroke="#000000"
                strokeWidth="1.4"
                strokeLinecap="round"
              />
              <path
                d="M3.5 7C6 4.9 10 4.9 12.5 7"
                stroke="#000000"
                strokeWidth="1.4"
                strokeLinecap="round"
              />
              <path
                d="M6.3 9.3C7.2 8.6 8.8 8.6 9.7 9.3"
                stroke="#000000"
                strokeWidth="1.4"
                strokeLinecap="round"
              />
              <circle cx="8" cy="10.4" r="1" fill="#000000" />
            </svg>

            <div className="relative h-[12px] w-[25px] rounded-[3px] border-[1.6px] border-black">
              <div className="absolute left-[1.5px] top-[1.5px] h-[7px] w-[18px] rounded-[2px] bg-black" />
              <div className="absolute -right-[3px] top-[3px] h-[4px] w-[2px] rounded-r-[1px] bg-black" />
            </div>
          </div>
        </div>

        {/* Back action */}
        <button
          type="button"
          onClick={() => navigate('/')}
          className="mt-[14px] flex w-fit items-center gap-[6px] text-[16px] font-medium text-black"
        >
          <svg width="10" height="16" viewBox="0 0 10 16" fill="none">
            <path
              d="M8 2L2 8L8 14"
              stroke="#000000"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            />
          </svg>
          <span>Back</span>
        </button>

        {/* Title section */}
        <div className="mt-[26px]">
          <h1 className="text-[32px] font-bold leading-none text-black">Log In</h1>
          <p className="mt-[10px] text-[18px] font-medium text-black">Welcome Back !</p>
        </div>

        {/* Form section */}
        <form onSubmit={handleSubmit} className="mt-[36px] flex flex-col">
          <div className="space-y-[16px]">
            <div className="flex h-[54px] items-center rounded-[10px] bg-[#f3f3f3] px-[16px]">
              <img src={phoneIcon} alt="Identifier" className="h-[20px] w-[20px] object-contain opacity-70" />
              <input
                type="text"
                name="identifier"
                placeholder="Phone Number or Email"
                value={formData.identifier}
                onChange={handleChange}
                className="ml-[12px] flex-1 bg-transparent text-[16px] text-black outline-none placeholder:text-[#9b9b9b]"
                required
              />
            </div>

            <div className="flex h-[54px] items-center rounded-[10px] bg-[#f3f3f3] px-[16px]">
              <svg width="18" height="22" viewBox="0 0 18 22" fill="none" aria-hidden="true">
                <path
                  d="M4 9V6.8C4 4 6.2 2 9 2C11.8 2 14 4 14 6.8V9"
                  stroke="#7D7D7D"
                  strokeWidth="1.8"
                  strokeLinecap="round"
                />
                <rect x="2" y="9" width="14" height="11" rx="3" stroke="#7D7D7D" strokeWidth="1.8" />
              </svg>

              <input
                type="password"
                name="password"
                placeholder="Password"
                value={formData.password}
                onChange={handleChange}
                className="ml-[12px] flex-1 bg-transparent text-[16px] text-black outline-none placeholder:text-[#9b9b9b]"
                required
              />
            </div>
          </div>

          {errorMessage && (
            <div className="mt-[14px] rounded-[10px] bg-red-100 px-4 py-3 text-[13px] text-red-700">
              {errorMessage}
            </div>
          )}

          <div className="mt-[12px] flex justify-end">
            <span className="text-[14px] font-medium text-[#7d7d7d]">Forgot Password?</span>
          </div>

          <button
            type="submit"
            disabled={isSubmitting}
            className="mt-[18px] h-[46px] w-full rounded-[9px] bg-[#c8c8c8] text-[18px] font-semibold text-white disabled:opacity-70"
          >
            {isSubmitting ? 'Logging In...' : 'Log In'}
          </button>
        </form>

        {/* Bottom section */}
        <div className="mt-auto pb-[8px]">
          <div className="flex items-center justify-center gap-[12px]">
            <div className="h-[1px] flex-1 bg-[#8a8a8a]" />
            <span className="text-[15px] text-black">or</span>
            <div className="h-[1px] flex-1 bg-[#8a8a8a]" />
          </div>

          <div className="mt-[16px] flex items-center justify-center gap-[24px]">
            <img src={facebookIcon} alt="Facebook" className="h-[36px] w-[36px] object-contain" />
            <img src={googleIcon} alt="Google" className="h-[36px] w-[36px] object-contain" />
            <img src={emailIcon} alt="Email" className="h-[36px] w-[36px] object-contain" />
            <img src={phoneIcon} alt="Phone" className="h-[36px] w-[36px] object-contain" />
          </div>

          <div className="mt-[18px] flex items-center justify-center gap-[4px] text-[15px]">
            <span className="text-[#7d7d7d]">Don&apos;t have an account?</span>
            <button
              type="button"
              onClick={() => navigate('/register')}
              className="font-semibold text-black"
            >
              Register here
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
